public static long solve(String s) {
    int n = s.length();
    long[] prefix_L = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefix_L[i + 1] = prefix_L[i] + (s.charAt(i) == 'L' ? 1 : 0);
    }

    long[] T_count = new long[n + 1];
    T_count[n] = 0;
    for (int i = n - 1; i >= 0; i--) {
        T_count[i] = T_count[i + 1] + (s.charAt(i) == 'T' ? 1 : 0);
    }

    long[] postCT = new long[n + 1];
    postCT[n] = 0;
    for (int i = n - 1; i >= 0; i--) {
        postCT[i] = postCT[i + 1];
        if (s.charAt(i) == 'C') {
            postCT[i] += T_count[i + 1];
        }
    }

    long[] prefix_LC = new long[n + 1];
    prefix_LC[0] = 0;
    long L_so_far = 0;
    for (int i = 0; i < n; i++) {
        prefix_LC[i + 1] = prefix_LC[i];
        if (s.charAt(i) == 'L') {
            L_so_far++;
        } else if (s.charAt(i) == 'C') {
            prefix_LC[i + 1] += L_so_far;
        }
    }

    long total0 = 0;
    for (int j = 0; j < n; j++) {
        if (s.charAt(j) == 'C') {
            long leftL = prefix_L[j];
            long rightT = T_count[j + 1];
            total0 += leftL * rightT;
        }
    }

    long ans = total0;
    for (int i = 0; i <= n; i++) {
        ans = Math.max(ans, total0 + postCT[i]);
    }
    for (int i = 0; i <= n; i++) {
        ans = Math.max(ans, total0 + prefix_L[i] * T_count[i]);
    }
    for (int i = 0; i <= n; i++) {
        ans = Math.max(ans, total0 + prefix_LC[i]);
    }

    return ans;
}
