public class Solution {
    public static long solve(String s) {
        if (s == null || s.isEmpty()) {
            return 0;
        }
        int n = s.length();

        long base = 0;
        long countL = 0;
        long countLC = 0;
        long countLCT = 0;
        for (int i = 0; i < n; i++) {
            char c = s.charAt(i);
            if (c == 'L') {
                countL++;
            } else if (c == 'C') {
                countLC += countL;
            } else if (c == 'T') {
                countLCT += countLC;
            }
        }
        base = countLCT;

        long[] prefixL = new long[n + 1];
        prefixL[0] = 0;
        for (int i = 0; i < n; i++) {
            prefixL[i + 1] = prefixL[i] + (s.charAt(i) == 'L' ? 1 : 0);
        }

        long[] prefixLC = new long[n + 1];
        prefixLC[0] = 0;
        long runL = 0;
        for (int i = 0; i < n; i++) {
            char c = s.charAt(i);
            if (c == 'L') {
                runL++;
                prefixLC[i + 1] = prefixLC[i];
            } else if (c == 'C') {
                prefixLC[i + 1] = prefixLC[i] + runL;
            } else {
                prefixLC[i + 1] = prefixLC[i];
            }
        }

        long[] suffixT = new long[n + 1];
        suffixT[n] = 0;
        for (int i = n - 1; i >= 0; i--) {
            suffixT[i] = suffixT[i + 1] + (s.charAt(i) == 'T' ? 1 : 0);
        }

        long[] suffixCT = new long[n + 1];
        suffixCT[n] = 0;
        long runT = 0;
        for (int i = n - 1; i >= 0; i--) {
            char c = s.charAt(i);
            if (c == 'T') {
                runT++;
                suffixCT[i] = suffixCT[i + 1];
            } else if (c == 'C') {
                suffixCT[i] = suffixCT[i + 1] + runT;
            } else {
                suffixCT[i] = suffixCT[i + 1];
            }
        }

        long ans = base;
        for (int i = 0; i <= n; i++) {
            long cand1 = base + suffixCT[i];
            long cand2 = base + prefixL[i] * suffixT[i];
            long cand3 = base + prefixLC[i];
            if (cand1 > ans) ans = cand1;
            if (cand2 > ans) ans = cand2;
            if (cand3 > ans) ans = cand3;
        }

        return ans;
    }
}
